async function apiGetJson<T>(
  doFetch: typeof fetch,
  url: string,
  headers: Record<string, string>,
  fallback: T,
  sleep: (ms: number) => Promise<void>,
  opts: { strict?: boolean } = {},
): Promise<T> {
  for (let attempt = 0; attempt < 3; attempt++) {
    let res: Response;
    try {
      res = await doFetch(url, { headers });
    } catch {
      if (opts.strict) throw new Error(`discord api network error: ${url}`);
      return fallback;
    }
    if (res.status === 429) {
      const retry = await res.json().then((j: { retry_after?: number }) => j.retry_after ?? 1).catch(() => 1);
      await sleep(Math.ceil(retry * 1000) + 250);
      continue;
    }
    if (!res.ok) {
      if (opts.strict) throw new Error(`discord api ${res.status}: ${url}`);
      return fallback;
    }
    try {
      return (await res.json()) as T;
    } catch {
      if (opts.strict) throw new Error(`discord api invalid json: ${url}`);
      return fallback;
    }
  }
  if (opts.strict) throw new Error(`discord api rate-limited after retries: ${url}`);
  return fallback;
}

